const canAccessSection = (
  role: UserRole,
  section: AccessSection,
  permissions?: string[] | null
): boolean => {
  if (role === 'admin' || role === 'admin2') {
    return true;
  }

  if (Array.isArray(permissions)) {
    if (permissions.includes(section)) {
      return true;
    }

    if (section === 'bdd-activos-asesores') {
      return role === 'asesor';
    }

    return false;
  }

  switch (section) {
    case 'distriapp':
      return role !== 'operator' && role !== 'asesor';
    case 'usuarios':
    case 'rrhh':
    case 'control-horario':
    case 'liquidaciones':
    case 'pagos':
    case 'facturacion':
    case 'combustible':
    case 'auditoria':
    case 'configuracion':
      return false;
    case 'clientes':
    case 'panel-general':
    case 'resumen':
    case 'unidades':
      return role !== 'operator' && role !== 'asesor';
    case 'reclamos':
      return true; // Todos los roles pueden crear/ver reclamos (incluido asesor)
    case 'personal':
      return role === 'asesor' || role === 'encargado';
    case 'tarifas':
      return true;
    case 'ticketera':
    case 'notificaciones':
    case 'flujo-trabajo':
    case 'aprobaciones':
    case 'solicitud-personal':
    case 'bases':
    case 'documentos':
      return true;
    case 'bdd-activos-asesores':
      return role === 'asesor';
    default:
      return true;
  }
};

